<?php
function processXmlConfig($xmlString) {
    // Load the XML string into a SimpleXML object
    $xml = simplexml_load_string($xmlString);

    if ($xml === false) {
        throw new Exception('Failed to load XML string.');
    }

    // Extract settings from the XML
    $settings = [];
    foreach ($xml->children() as $child) {
        $settings[(string)$child['name']] = (string)$child;
    }

    return $settings;
}

// Example usage:
try {
    $xmlString = '<?xml version="1.0" encoding="UTF-8"?>
    <config>
        <setting name="database_host">localhost</setting>
        <setting name="database_name">mydb</setting>
        <setting name="database_user">user</setting>
        <setting name="database_password">pass</setting>
    </config>';

    $settings = processXmlConfig($xmlString);
    print_r($settings);
} catch (Exception $e) {
    echo 'Error: ' . $e->getMessage();
